import ldap

def search_users_by_username(ldap_server, bind_dn, bind_password, search_base, username):
    try:
        # Initialize LDAP connection
        ldap_conn = ldap.initialize(ldap_server)
        ldap_conn.protocol_version = ldap.VERSION3
        ldap_conn.set_option(ldap.OPT_REFERRALS, 0)
        
        # Bind to the directory
        ldap_conn.simple_bind_s(bind_dn, bind_password)
        
        # Search for user by username
        search_filter = f"(&(objectClass=user)(sAMAccountName={username}))"
        attributes = ['cn', 'sAMAccountName', 'mail', 'displayName']
        
        result = ldap_conn.search_s(search_base, ldap.SCOPE_SUBTREE, search_filter, attributes)
        
        # Process results
        users = []
        for dn, entry in result:
            if entry:
                user_info = {
                    'dn': dn,
                    'cn': entry.get('cn', [b''])[0].decode('utf-8') if entry.get('cn') else '',
                    'sAMAccountName': entry.get('sAMAccountName', [b''])[0].decode('utf-8') if entry.get('sAMAccountName') else '',
                    'mail': entry.get('mail', [b''])[0].decode('utf-8') if entry.get('mail') else '',
                    'displayName': entry.get('displayName', [b''])[0].decode('utf-8') if entry.get('displayName') else ''
                }
                users.append(user_info)
        
        # Close connection
        ldap_conn.unbind_s()
        
        return users
        
    except ldap.INVALID_CREDENTIALS:
        raise Exception("Invalid credentials")
    except ldap.NO_SUCH_OBJECT:
        raise Exception("Search base not found")
    except ldap.LDAPError as e:
        raise Exception(f"LDAP error: {e}")